def solve(nums: Array[Long]): Long = {
  import scala.collection.mutable.HashMap
  import scala.collection.mutable.PriorityQueue

  val n = nums.length
  val sorted = nums.sorted

  if (nums.toList == sorted) return 0L

  val map = HashMap[Long, List[Int]]()
  for (i <- 0 until n) {
    map.put(nums(i), map.getOrElse(nums(i), List()).append(i))
  }

  val pq = PriorityQueue[Long](Ordering.Long.reverse)
  for (i <- 0 until n) {
    val k = nums(i)
    for (j <- map.getOrElse(k, List())) {
      if (i < j && (nums(i) & nums(j)) == k) {
        pq.add(k)
      }
    }
  }

  pq.head
}
